{
  "copy": "<!-- Last modified Wed Sep 17 2:34PM --><!-- Page: lvxcpquery -->
<div class="container-fluid mt-4">
  <div class="row"><div class="col-12"></div></div>
  <!-- Date Range Controls -->
  <div class="row mb-4">
    <div class="col-12">
      <div class="card" style="box-shadow: rgba(0, 0, 0, 0.075) 0px 0.125rem 0.25rem;">
        <div class="card-header"><h5 class="mb-0">Query Parameters 2509020745</h5></div>
        <div class="card-body">
          <div class="row g-3">
            <div class="col-md-4">
              <label for="dateRangePreset" class="form-label">Quick Select:</label
              ><select id="dateRangePreset" onchange="applyDateRangePreset()" class="form-control">
                <option value="">-- Select Range --</option>
                <option value="lastHour">Last Hour</option>
                <option value="today" selected="">Today</option>
                <option value="todayYesterday">Today and Yesterday</option>
                <option value="last7Days">Last 7 Days</option>
                <option value="last30Days">Last 30 Days</option>
              </select>
            </div>
            <div class="col-md-4"><label for="fromDate" class="form-label">From Date:</label><input type="datetime-local" id="fromDate" name="fromDate" class="form-control" /></div>
            <div class="col-md-4"><label for="thruDate" class="form-label">Thru Date:</label><input type="datetime-local" id="thruDate" name="thruDate" class="form-control" /></div>
          </div>
          <div class="row mt-3">
            <div class="col-md-12">
              <label for="tableSelect" class="form-label">Table to Query:</label
              ><select id="tableSelect" onchange="onTableChange()" class="form-control">
                <option value="lv_logs" selected="">lv_logs (User Activity Log)</option>
                <option value="lv_lvcomploanofficers">lv_lvcomploanofficers (Loan Officers)</option>
                <option value="lv_lvcompcommissions">lv_lvcompcommissions (Commissions)</option>
                <option value="lv_lvcompbranchs">lv_lvcompbranchs (Branches)</option>
              </select>
            </div>
          </div>
          <div class="row mt-3">
            <div class="col-md-6"><label for="txtUserFilter" class="form-label">User Name Filter (Regex):</label><input type="text" id="txtUserFilter" placeholder="Enter regex pattern or use presets below" oninput="applyUserFilter()" class="form-control" /></div>
            <div class="col-md-6">
              <label for="ddlUserFilterPresets" class="form-label">User Filter Presets:</label
              ><select id="ddlUserFilterPresets" onchange="applyUserFilterPreset()" class="form-control">
                <option value="">-- Common User Filters --</option>
                <option value="^(?!.*Loan Vision).*$">Exclude "Loan Vision"</option>
                <option value="^(?!.*Robert Martin).*$">Exclude "Robert Martin"</option>
                <option value="^(?!.*Loanvisiontesting)(?!.*Loan Vision)(?!.*Robert Martin)(?!.*Michael LeBuhn).*$">Exclude "Loanvisiontesting", "Loan Vision", "Robert Martin", and "Michael LeBuhn"</option>
                <option value=".*">Show All Users</option>
                <option value=".*Robert Martin.*">Only "Robert Martin"</option>
                <option value=".*Loan Vision.*">Only "Loan Vision"</option>
              </select>
            </div>
          </div>
          <div class="row mt-3">
            <div class="col-12">
              <button type="button" onclick="executeQuery()" class="btn btn-primary"><i class="fas fa-search"></i> Execute Query</button><button type="button" onclick="resetDates()" class="btn btn-secondary ms-2"><i class="fas fa-refresh"></i> Reset</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <!-- Results Table -->
  <div class="row">
    <div class="col-12">
      <div class="card" style="box-shadow: rgba(0, 0, 0, 0.075) 0px 0.125rem 0.25rem;">
        <div class="card-header d-flex justify-content-between align-items-center">
          <h5 class="mb-0">
            Query Results <small class="text-muted">(<span id="resultCount">0</span> records)</small>
          </h5>
          <div id="statusBadge" class="badge bg-secondary" style="font-size: 0.75em; min-width: 80px; text-align: center;">Ready</div>
        </div>
        <div class="card-body">
          <div class="table-responsive" style="max-height: 600px; overflow-y: auto;">
            <table id="resultsTable" class="table table-striped table-hover">
              <thead class="table-dark">
                <tr>
                  <th>When</th>
                  <th>User</th>
                  <th>Kind</th>
                  <th>Detail/Memo</th>
                </tr>
              </thead>
              <tbody id="resultsBody">
                <tr style="background-color: rgba(0, 0, 0, 0.024);" bgcolor="rgba(0, 0, 0, 0.024)">
                  <td colspan="4" class="text-center text-muted"><i class="fas fa-info-circle"></i> Click "Execute Query" to load results</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
<script>
  // Table configurations for different schemas - Based on Data Dictionary
  const tableConfigs = {
      'lv_logs': {
          dateField: 'createdon',
          userField: 'lv_userfullname',
          selectFields: 'createdon,lv_userfullname,lv_kind,lv_detail,lv_memo',
          headers: ['When', 'User', 'Kind', 'Detail/Memo'],
          displayFunction: displayLogsResults,
          supportsDateFilter: true
      },
      'lv_lvcomploanofficers': {
          dateField: null,
          userField: 'lv_name',
          selectFields: 'lv_name,lv_code,lv_branchname,lv_emailaddress',
          headers: ['Name', 'Code', 'Branch', 'Email'],
          displayFunction: displayLoanOfficerResults,
          supportsDateFilter: false
      },
      'lv_lvcompcommissions': {
          dateField: 'lv_commissiondate',
          userField: 'lv_xloanofficername',
          selectFields: 'lv_commissiondate,lv_xloanofficername,lv_xloanofficercode,lv_xbranchname,lv_amount',
          headers: ['Commission Date', 'Loan Officer', 'Code', 'Branch', 'Amount'],
          displayFunction: displayCommissionResults,
          supportsDateFilter: true
      },
      'lv_lvcompbranchs': {
          dateField: null,
          userField: 'lv_name',
          selectFields: 'lv_name,lv_code',
          headers: ['Branch Name', 'Code'],
          displayFunction: displayBranchResults,
          supportsDateFilter: false
      }
  };

  function onTableChange() {
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];

      // Update table headers
      const headerRow = document.querySelector('#resultsTable thead tr');
      headerRow.innerHTML = '';
      config.headers.forEach(header => {
          headerRow.innerHTML += `<th>${header}</th>`;
      });

      // Clear existing results
      const tbody = document.getElementById('resultsBody');
      tbody.innerHTML = `
          <tr>
              <td colspan="${config.headers.length}" class="text-center text-muted">
                  <i class="fas fa-info-circle"></i> Click "Execute Query" to load results
              </td>
          </tr>
      `;
      document.getElementById('resultCount').textContent = '0';
      document.getElementById('statusBadge').textContent = 'Ready';
      document.getElementById('statusBadge').className = 'badge bg-secondary';
  }

  function applyDateRangePreset() {
      const preset = document.getElementById('dateRangePreset').value;
      const now = new Date();

      let fromDate, thruDate;

      switch (preset) {
          case 'lastHour':
              fromDate = new Date(now.getTime() - (60 * 60 * 1000)); // 1 hour ago
              thruDate = now;
              break;
          case 'today':
              fromDate = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
              thruDate = now;
              break;
          case 'todayYesterday':
              fromDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1, 0, 0, 0);
              thruDate = now;
              break;
          case 'last7Days':
              fromDate = new Date(now.getTime() - (7 * 24 * 60 * 60 * 1000));
              thruDate = now;
              break;
          case 'last30Days':
              fromDate = new Date(now.getTime() - (30 * 24 * 60 * 60 * 1000));
              thruDate = now;
              break;
          default:
              return; // Don't update if no preset selected
      }

      // Format for datetime-local input (YYYY-MM-DDTHH:MM)
      document.getElementById('fromDate').value = fromDate.toISOString().slice(0, 16);
      document.getElementById('thruDate').value = thruDate.toISOString().slice(0, 16);
  }

  function resetDates() {
      // Set "Today" as default
      document.getElementById('dateRangePreset').value = 'today';
      applyDateRangePreset();

      // Clear user filter
      document.getElementById('txtUserFilter').value = '';
      document.getElementById('ddlUserFilterPresets').selectedIndex = 0;

      // Clear results
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      tbody.innerHTML = `
          <tr>
              <td colspan="${config.headers.length}" class="text-center text-muted">
                  <i class="fas fa-info-circle"></i> Click "Execute Query" to load results
              </td>
          </tr>
      `;
      document.getElementById('resultCount').textContent = '0';
      document.getElementById('statusBadge').textContent = 'Ready';
      document.getElementById('statusBadge').className = 'badge bg-secondary';
  }

  async function executeQuery() {
      const fromDate = document.getElementById('fromDate').value;
      const thruDate = document.getElementById('thruDate').value;
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];

      // Only require dates for tables that support date filtering
      if (config.supportsDateFilter) {
          if (!fromDate || !thruDate) {
              alert('Please select both From and Thru dates');
              return;
          }

          if (fromDate > thruDate) {
              alert('From date cannot be later than Thru date');
              return;
          }
      }

      // Update status
      document.getElementById('statusBadge').textContent = 'Loading...';
      document.getElementById('statusBadge').className = 'badge bg-warning';

      // Show loading in table
      const tbody = document.getElementById('resultsBody');
      tbody.innerHTML = `
          <tr>
              <td colspan="${config.headers.length}" class="text-center">
                  <i class="fas fa-spinner fa-spin"></i> Loading data...
              </td>
          </tr>
      `;

      // Build API query
      let apiUrl;
      if (config.supportsDateFilter) {
          // Build API query with date filters - fromDate and thruDate are already in format YYYY-MM-DDTHH:MM
          const fromDateTime = fromDate + ':00Z'; // Add seconds and Z for UTC
          const thruDateTime = thruDate + ':59Z'; // Add seconds and Z for UTC

          apiUrl = `/_api/${selectedTable}?$filter=${config.dateField} ge ${fromDateTime} and ${config.dateField} le ${thruDateTime}&$orderby=${config.dateField} desc&$select=${config.selectFields}`;
      } else {
          // Simple query without date filtering, limit to 100 records
          apiUrl = `/_api/${selectedTable}?$top=100&$select=${config.selectFields}`;
      }

      console.log('API URL:', apiUrl);

      try {
          const response = await apiCall(apiUrl, 'GET', '', true);
          console.log('API Response:', response);

          if (response.success && response.data && response.data.value) {
              config.displayFunction(response.data.value);
          } else if (response.data && Array.isArray(response.data)) {
              // Handle case where data is directly an array
              config.displayFunction(response.data);
          } else {
              throw new Error(response.message || 'Unknown API error');
          }
      } catch (error) {
          console.error('Query error:', error);
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-danger">
                      <i class="fas fa-exclamation-triangle"></i> Error loading data: ${error.message || error}
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'Error';
          document.getElementById('statusBadge').className = 'badge bg-danger';
      }
  }

  function displayLogsResults(results) {
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      const resultCount = results.length;

      document.getElementById('resultCount').textContent = resultCount;

      if (resultCount === 0) {
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-muted">
                      <i class="fas fa-search"></i> No records found for the selected date range
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'No Results';
          document.getElementById('statusBadge').className = 'badge bg-info';
          return;
      }

      let tableRows = '';
      results.forEach(row => {
          const createdDate = new Date(row.createdon);
          const whenText = minutesAgo(createdDate);
          const fullDateTitle = createdDate.toLocaleDateString('en-US', {
              weekday: 'short',
              day: 'numeric',
              month: 'short',
              hour: '2-digit',
              minute: '2-digit',
              second: '2-digit',
              hour12: true
          });
          const user = row.lv_userfullname || 'Unknown';
          const kind = row.lv_kind || '';
          const details = row.lv_detail || row.lv_memo || '';

          tableRows += `
              <tr class="query-result-row" data-username="${user}">
                  <td class="date-column" title="${fullDateTitle}">${whenText}</td>
                  <td>${user}</td>
                  <td><span class="badge bg-light text-dark">${kind}</span></td>
                  <td class="text-truncate" style="max-width: 500px;" title="${details}">${details}</td>
              </tr>
          `;
      });

      tbody.innerHTML = tableRows;
      document.getElementById('statusBadge').textContent = `${resultCount} Results`;
      document.getElementById('statusBadge').className = 'badge bg-success';

      // Apply any existing user filter to the new results
      const userFilterValue = document.getElementById('txtUserFilter').value.trim();
      if (userFilterValue) {
          applyUserFilter();
      }
  }

  function displayLoanOfficerResults(results) {
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      const resultCount = results.length;

      document.getElementById('resultCount').textContent = resultCount;

      if (resultCount === 0) {
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-muted">
                      <i class="fas fa-search"></i> No records found
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'No Results';
          document.getElementById('statusBadge').className = 'badge bg-info';
          return;
      }

      let tableRows = '';
      results.forEach(row => {
          const name = row.lv_name || 'Unknown';
          const code = row.lv_code || '';
          const branch = row.lv_branchname || '';
          const email = row.lv_emailaddress || '';

          tableRows += `
              <tr class="query-result-row" data-username="${name}">
                  <td>${name}</td>
                  <td><span class="badge bg-light text-dark">${code}</span></td>
                  <td>${branch}</td>
                  <td>${email}</td>
              </tr>
          `;
      });

      tbody.innerHTML = tableRows;
      document.getElementById('statusBadge').textContent = `${resultCount} Results`;
      document.getElementById('statusBadge').className = 'badge bg-success';

      // Apply any existing user filter to the new results
      const userFilterValue = document.getElementById('txtUserFilter').value.trim();
      if (userFilterValue) {
          applyUserFilter();
      }
  }

  function displayCommissionResults(results) {
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      const resultCount = results.length;

      document.getElementById('resultCount').textContent = resultCount;

      if (resultCount === 0) {
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-muted">
                      <i class="fas fa-search"></i> No records found for the selected date range
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'No Results';
          document.getElementById('statusBadge').className = 'badge bg-info';
          return;
      }

      let tableRows = '';
      results.forEach(row => {
          const commissionDate = new Date(row.lv_commissiondate);
          const whenText = commissionDate.toLocaleDateString('en-US', {
              month: 'short',
              day: 'numeric'
          });
          const fullDateTitle = commissionDate.toLocaleDateString('en-US', {
              weekday: 'short',
              day: 'numeric',
              month: 'short',
              year: 'numeric'
          });
          const name = row.lv_xloanofficername || 'Unknown';
          const code = row.lv_xloanofficercode || '';
          const branch = row.lv_branchname || '';
          const amount = row.lv_amount ? '
</script>
