      document.getElementById('resultCount').textContent = '0';
      document.getElementById('statusBadge').textContent = 'Ready';
      document.getElementById('statusBadge').className = 'badge bg-secondary';
  }

  function applyDateRangePreset() {
      const preset = document.getElementById('dateRangePreset').value;
      const now = new Date();

      let fromDate, thruDate;

      switch (preset) {
          case 'lastHour':
              fromDate = new Date(now.getTime() - (60 * 60 * 1000)); // 1 hour ago
              thruDate = now;
              break;
          case 'today':
              fromDate = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
              thruDate = now;
              break;
          case 'todayYesterday':
              fromDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1, 0, 0, 0);
              thruDate = now;
              break;
          case 'last7Days':
              fromDate = new Date(now.getTime() - (7 * 24 * 60 * 60 * 1000));
              thruDate = now;
              break;
          case 'last30Days':
              fromDate = new Date(now.getTime() - (30 * 24 * 60 * 60 * 1000));
              thruDate = now;
              break;
          default:
              return; // Don't update if no preset selected
      }

      // Format for datetime-local input (YYYY-MM-DDTHH:MM)
      document.getElementById('fromDate').value = fromDate.toISOString().slice(0, 16);
      document.getElementById('thruDate').value = thruDate.toISOString().slice(0, 16);
  }

  function resetDates() {
      // Set "Today" as default
      document.getElementById('dateRangePreset').value = 'today';
      applyDateRangePreset();

      // Clear user filter
      document.getElementById('txtUserFilter').value = '';
      document.getElementById('ddlUserFilterPresets').selectedIndex = 0;

      // Clear results
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      tbody.innerHTML = `
          <tr>
              <td colspan="${config.headers.length}" class="text-center text-muted">
                  <i class="fas fa-info-circle"></i> Click "Execute Query" to load results
              </td>
          </tr>
      `;
      document.getElementById('resultCount').textContent = '0';
      document.getElementById('statusBadge').textContent = 'Ready';
      document.getElementById('statusBadge').className = 'badge bg-secondary';
  }

  async function executeQuery() {
      const fromDate = document.getElementById('fromDate').value;
      const thruDate = document.getElementById('thruDate').value;
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];

      // Only require dates for tables that support date filtering
      if (config.supportsDateFilter) {
          if (!fromDate || !thruDate) {
              alert('Please select both From and Thru dates');
              return;
          }

          if (fromDate > thruDate) {
              alert('From date cannot be later than Thru date');
              return;
          }
      }

      // Update status
      document.getElementById('statusBadge').textContent = 'Loading...';
      document.getElementById('statusBadge').className = 'badge bg-warning';

      // Show loading in table
      const tbody = document.getElementById('resultsBody');
      tbody.innerHTML = `
          <tr>
              <td colspan="${config.headers.length}" class="text-center">
                  <i class="fas fa-spinner fa-spin"></i> Loading data...
              </td>
          </tr>
      `;

      // Build API query
      let apiUrl;
      if (config.supportsDateFilter) {
          // Build API query with date filters - fromDate and thruDate are already in format YYYY-MM-DDTHH:MM
          const fromDateTime = fromDate + ':00Z'; // Add seconds and Z for UTC
          const thruDateTime = thruDate + ':59Z'; // Add seconds and Z for UTC

          apiUrl = `/_api/${selectedTable}?$filter=${config.dateField} ge ${fromDateTime} and ${config.dateField} le ${thruDateTime}&$orderby=${config.dateField} desc&$select=${config.selectFields}`;
      } else {
          // Simple query without date filtering, limit to 100 records
          apiUrl = `/_api/${selectedTable}?$top=100&$select=${config.selectFields}`;
      }

      console.log('API URL:', apiUrl);

      try {
          const response = await apiCall(apiUrl, 'GET', '', true);
          console.log('API Response:', response);

          if (response.success && response.data && response.data.value) {
              config.displayFunction(response.data.value);
          } else if (response.data && Array.isArray(response.data)) {
              // Handle case where data is directly an array
              config.displayFunction(response.data);
          } else {
              throw new Error(response.message || 'Unknown API error');
          }
      } catch (error) {
          console.error('Query error:', error);
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-danger">
                      <i class="fas fa-exclamation-triangle"></i> Error loading data: ${error.message || error}
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'Error';
          document.getElementById('statusBadge').className = 'badge bg-danger';
      }
  }

  function displayLogsResults(results) {
      const selectedTable = document.getElementById('tableSelect').value;
      const config = tableConfigs[selectedTable];
      const tbody = document.getElementById('resultsBody');
      const resultCount = results.length;

      document.getElementById('resultCount').textContent = resultCount;

      if (resultCount === 0) {
          tbody.innerHTML = `
              <tr>
                  <td colspan="${config.headers.length}" class="text-center text-muted">
                      <i class="fas fa-search"></i> No records found for the selected date range
                  </td>
              </tr>
          `;
          document.getElementById('statusBadge').textContent = 'No Results';
          document.getElementById('statusBadge').className = 'badge bg-info';
          return;
      }

      let tableRows = '';
      results.forEach(row => {
          const createdDate = new Date(row.createdon);
          const whenText = minutesAgo(createdDate);
          const fullDateTitle = createdDate.toLocaleDateString('en-US', {
              weekday: 'short',
              day: 'numeric',
              month: 'short',
              hour: '2-digit',
              minute: '2-digit',
              second: '2-digit',
              hour12: true
          });
          const user = row.lv_userfullname || 'Unknown';
          const kind = row.lv_kind || '';
          const details = row.lv_detail || row.lv_memo || '';

          tableRows += `
              <tr class="query-result-row" data-username="${user}">
                  <td class="date-column" title="${fullDateTitle}">${whenText}</td>
                  <td>${user}</td>
                  <td><span class="badge bg-light text-dark">${kind}</span></td>
                  <td class="text-truncate" style="max-width: 500px;" title="${details}">${details}</td>
              </tr>
          `;
      });

      tbody.innerHTML = tableRows;
      document.getElementById('statusBadge').textContent = `${resultCount} Results`;
      document.getElementById('statusBadge').className = 'badge bg-success';

      // Apply any existing user filter to the new results
      const userFilterValue = document.getElementById('txtUserFilter').value.trim();
      if (userFilterValue) {
          applyUserFilter();
      }
  }

